// Build the Weekly Action Plan email.

const response = $input.first().json;
const user = $('Loop Over Users').item.json;

// If generation failed or returned no plan, skip
if (!response.ok || !response.plan) {
  console.log(`Skipping email for ${user.org_name} — plan generation failed`);
  return [];
}

const plan = response.plan;
const metrics = plan.metrics || {};

// Format currency
function fmt(n) {
  if (!n) return '£0';
  if (n >= 1000000) return '£' + (n / 1000000).toFixed(1) + 'm';
  if (n >= 1000) return '£' + Math.round(n / 1000) + 'k';
  return '£' + n.toLocaleString('en-GB');
}

// Build task list HTML
function taskListHtml(tasks) {
  if (!tasks || tasks.length === 0) return '<p style="color:#6B7280;font-size:14px">No tasks this week.</p>';
  return tasks.map(t => `
    <div style="background:#f9fafb;border-radius:10px;padding:14px 16px;margin-bottom:10px">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px">
        <strong style="color:#0D1117;font-size:14px;line-height:1.4">${t.title}</strong>
        <span style="color:#9CA3AF;font-size:12px;white-space:nowrap;flex-shrink:0">~${t.estimated_minutes} min</span>
      </div>
      <p style="color:#6B7280;font-size:13px;margin:6px 0 0;line-height:1.5">${t.description}</p>
      ${t.link ? `<a href="https://fundsradar.co${t.link}" style="color:#0F4C35;font-size:12px;font-weight:600;text-decoration:none">Go to ${t.link.replace('/', '')} →</a>` : ''}
    </div>
  `).join('');
}

const urgentHtml   = taskListHtml(plan.urgent);
const importantHtml = taskListHtml(plan.important);
const socialHtml   = taskListHtml(plan.social_media);

// Get current Monday
const now = new Date();
const day = now.getUTCDay();
const diff = day === 0 ? -6 : 1 - day;
const monday = new Date(now);
monday.setUTCDate(now.getUTCDate() + diff);
const weekLabel = monday.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric', timeZone: 'UTC' });

const totalTasks = (plan.urgent?.length || 0) + (plan.important?.length || 0) + (plan.social_media?.length || 0);

const html = `
<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="font-family:'Segoe UI',Arial,sans-serif;background:#f4f6f5;margin:0;padding:24px">
  <div style="max-width:600px;margin:0 auto;background:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06)">

    <!-- Header -->
    <div style="background:#0F4C35;padding:28px 36px">
      <p style="color:rgba(255,255,255,0.6);font-size:13px;margin:0 0 4px;text-transform:uppercase;letter-spacing:0.05em">Week of ${weekLabel}</p>
      <h1 style="color:#ffffff;font-size:22px;margin:0 0 4px">Your Weekly Action Plan</h1>
      <p style="color:rgba(255,255,255,0.7);font-size:14px;margin:0">${user.org_name}</p>
    </div>

    <div style="padding:32px 36px">

      <!-- Metrics row -->
      <table style="width:100%;border-collapse:collapse;margin-bottom:28px">
        <tr>
          <td style="text-align:center;padding:12px;background:#f4f6f5;border-radius:10px;margin:4px">
            <div style="font-size:22px;font-weight:bold;color:#0F4C35">${metrics.trust_score || 0}/100</div>
            <div style="font-size:11px;color:#6B7280;margin-top:2px">Trust Score</div>
          </td>
          <td style="width:8px"></td>
          <td style="text-align:center;padding:12px;background:#f4f6f5;border-radius:10px">
            <div style="font-size:22px;font-weight:bold;color:#0D1117">${metrics.active_applications || 0}</div>
            <div style="font-size:11px;color:#6B7280;margin-top:2px">Active Apps</div>
          </td>
          <td style="width:8px"></td>
          <td style="text-align:center;padding:12px;background:${(metrics.grants_closing_week || 0) > 0 ? '#FEF3C7' : '#f4f6f5'};border-radius:10px">
            <div style="font-size:22px;font-weight:bold;color:${(metrics.grants_closing_week || 0) > 0 ? '#B45309' : '#0D1117'}">${metrics.grants_closing_week || 0}</div>
            <div style="font-size:11px;color:#6B7280;margin-top:2px">Closing Week</div>
          </td>
          <td style="width:8px"></td>
          <td style="text-align:center;padding:12px;background:#f4f6f5;border-radius:10px">
            <div style="font-size:18px;font-weight:bold;color:#0D1117">${fmt(metrics.total_potential)}</div>
            <div style="font-size:11px;color:#6B7280;margin-top:2px">Total Potential</div>
          </td>
        </tr>
      </table>

      <!-- Task count banner -->
      <div style="background:#E8F2ED;border-radius:10px;padding:12px 16px;margin-bottom:28px;text-align:center">
        <p style="color:#0F4C35;font-size:14px;font-weight:600;margin:0">You have ${totalTasks} action items this week</p>
      </div>

      <!-- URGENT -->
      <h2 style="color:#DC2626;font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:0.08em;margin:0 0 12px">🔴 Urgent This Week</h2>
      ${urgentHtml}

      <!-- IMPORTANT -->
      <h2 style="color:#B45309;font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:0.08em;margin:24px 0 12px">🟡 Important This Week</h2>
      ${importantHtml}

      <!-- SOCIAL MEDIA -->
      <h2 style="color:#7C3AED;font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:0.08em;margin:24px 0 12px">📱 Social Media This Week</h2>
      ${socialHtml}

      <!-- AI RECOMMENDATION -->
      ${plan.ai_recommendation ? `
      <div style="background:#0F4C35;border-radius:12px;padding:18px 20px;margin:24px 0">
        <h2 style="color:#00C875;font-size:13px;font-weight:700;text-transform:uppercase;letter-spacing:0.08em;margin:0 0 8px">💡 AI Recommendation</h2>
        <p style="color:rgba(255,255,255,0.9);font-size:14px;margin:0;line-height:1.6">${plan.ai_recommendation}</p>
      </div>
      ` : ''}

      <!-- CTA -->
      <div style="text-align:center;margin:28px 0 8px">
        <a href="https://fundsradar.co/weekly-plan" style="display:inline-block;background:#0F4C35;color:#ffffff;font-weight:bold;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:15px">View Full Plan →</a>
      </div>

      <p style="color:#9ca3af;font-size:12px;text-align:center;margin-top:20px">Sent every Monday · <a href="https://fundsradar.co/settings" style="color:#9ca3af">Manage preferences</a></p>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    to:      user.email,
    orgName: user.org_name,
    subject: `Your FundsRadar action plan for the week of ${weekLabel}`,
    html
  }
}];
